    { phrase: "Under the radar.", level: "advanced", translation: "低調 / 不被注意", meaning: "Not attracting much attention.", examples: ["The project is going under the radar for now.", "He likes to keep his personal life under the radar."] },
    { phrase: "Tip of the iceberg.", level: "advanced", translation: "冰山一角", meaning: "Only a small part of a much larger problem.", examples: ["This issue is just the tip of the iceberg.", "The discovered money is only the tip of the iceberg."] },
    { phrase: "Actions speak louder than words.", level: "advanced", translation: "事實勝於雄辯", meaning: "What you do is more important than what you say.", examples: ["He keeps saying he'll help, but actions speak louder than words.", "Success depends on work, not just promises. Actions speak louder than words."] },
    { phrase: "Go the extra mile.", level: "advanced", translation: "加倍努力", meaning: "To make a special effort to achieve something.", examples: ["Our employees are always willing to go the extra mile.", "He went the extra mile to make sure the event was a success."] },
    { phrase: "Kill two birds with one stone.", level: "advanced", translation: "一箭雙鵰", meaning: "To achieve two things at the same time.", examples: ["By biking to work, I'm exercising and saving money - killing two birds with one stone.", "Let's meet for lunch; we can catch up and discuss the project. Kill two birds with one stone."] },
    { phrase: "Let the cat out of the bag.", level: "advanced", translation: "洩露秘密", meaning: "To reveal a secret accidentally.", examples: ["I was trying to keep the party a secret, but Sarah let the cat out of the bag.", "Who let the cat out of the bag about the surprise?"] },
    { phrase: "On the fence.", level: "advanced", translation: "猶豫不決", meaning: "Being undecided about a choice.", examples: ["I'm still on the fence about whether to buy the car.", "She is on the fence regarding the new proposal."] },
    { phrase: "Spill the beans.", level: "advanced", translation: "洩密", meaning: "To give away a secret.", examples: ["Come on, spill the beans! What happened?", "He finally spilled the beans about the wedding."] },
    { phrase: "Take with a grain of salt.", level: "advanced", translation: "對...抱持懷疑態度", meaning: "To not believe something completely.", examples: ["You should take his stories with a grain of salt.", "I took the news with a grain of salt."] },
    { phrase: "Through thick and thin.", level: "advanced", translation: "患難與共", meaning: "In good times and bad times.", examples: ["They have been friends through thick and thin.", "He stayed with her through thick and thin."] },
    { phrase: "When pigs fly.", level: "advanced", translation: "太陽從西邊出來 (絕不可能)", meaning: "Something that will never happen.", examples: ["He'll clean his room when pigs fly.", "I'll agree to that when pigs fly."] },
    { phrase: "Wrap your head around something.", level: "advanced", translation: "理解某事", meaning: "To understand something complex.", examples: ["I can't quite wrap my head around the new theory.", "It took me a while to wrap my head around the decision."] },
    { phrase: "Your guess is as good as mine.", level: "advanced", translation: "我也拿不準", meaning: "I have no idea; I know as little as you do.", examples: ["Why is the train late? - Your guess is as good as mine.", "What will happen next? - Your guess is as good as mine."] },
    { phrase: "Best-case scenario.", level: "advanced", translation: "最好的情況", meaning: "The best possible result.", examples: ["In the best-case scenario, we'll finish early.", "This is the best-case scenario for the company."] },
    { phrase: "Devil's advocate.", level: "advanced", translation: "刻意唱反調者", meaning: "Someone who argues against an idea to test it.", examples: ["Let me play devil's advocate for a moment.", "He always plays devil's advocate in meetings."] },
    { phrase: "In a nutshell.", level: "advanced", translation: "簡而言之", meaning: "Very briefly; in a few words.", examples: ["In a nutshell, the project was a success.", "That's the situation in a nutshell."] },
    { phrase: "The whole nine yards.", level: "advanced", translation: "全部 / 徹頭徹尾", meaning: "Everything possible or available.", examples: ["He gave us the whole nine yards on his trip.", "We went for the whole nine yards for the party."] },
    { phrase: "Throw in the towel.", level: "advanced", translation: "認輸 / 放棄", meaning: "To admit defeat.", examples: ["He's not ready to throw in the towel yet.", "After three failures, they finally threw in the towel."] },
    { phrase: "Up in the air.", level: "advanced", translation: "懸而未決", meaning: "Not yet decided or settled.", examples: ["The plans for the summer are still up in the air.", "Our future is up in the air right now."] }
